+func newTempDiskDB(t *testing.T) (string, func()) {
+	t.Helper()
+	f, err := os.CreateTemp("", "imsg-disk-*.db")
+	if err != nil {
+		t.Fatalf("CreateTemp: %v", err)
+	}
+	path := f.Name()
+	_ = f.Close()
+	cleanup := func() { _ = os.Remove(path) }
+	return path, cleanup
